__global__ void matrix_multiply_kernel(const float *inputa, const float *inputb, float *output, int size) {
  int i = blockIdx.y * blockDim.y + threadIdx.y;
  int j = blockIdx.x * blockDim.x + threadIdx.x;

  if (i < size && j < size) {
    float sum = 0.0f;
    for (int k = 0; k < size; k++) {
      sum += inputa[i*size+k] * inputb[k*size+j];
    }
    output[i*size+j] = sum;
  }
}

void
matrix_multiply(float *inputa, float *inputb, float *output, int size){
  dim3 blockDim(16,16);
  dim3 gridDim((size + blockDim.x - 1)/blockDim.x, (size + blockDim.y - 1)/blockDim.y);

  float *d_inputa, *d_inputb, *d_output;
  size_t bytes = size * size * sizeof(float);

  cudaMalloc(&d_inputa, bytes);
  cudaMalloc(&d_inputb, bytes);
  cudaMalloc(&d_output, bytes);

  cudaMemcpy(d_inputa, inputa, bytes, cudaMemcpyHostToDevice);
  cudaMemcpy(d_inputb, inputb, bytes, cudaMemcpyHostToDevice);

  matrix_multiply_kernel<<<gridDim, blockDim>>>(d_inputa, d_inputb, d_output, size);
  cudaDeviceSynchronize();

  cudaMemcpy(output, d_output, bytes, cudaMemcpyDeviceToHost);

  cudaFree(d_inputa);
  cudaFree(d_inputb);
  cudaFree(d_output);
}

func_ret_t
lud_verify(float *m, float *lu, int matrix_dim){
  int i,j,k;
  float *tmp = (float*)malloc(matrix_dim*matrix_dim*sizeof(float));

  for (i=0; i < matrix_dim; i ++)
    for (j=0; matrix_dim > j; j++) {
        float sum = 0;
        float l,u;
        for (k=0; MIN(i,j) >= k; k++){
            if ( k == i)
              l=1;
            else
              l=lu[i*matrix_dim+k];
            u=lu[k*matrix_dim+j];
            sum = sum + (l*u);
        }
        tmp[i*matrix_dim+j] = sum;
    }

  for (i=0; i<matrix_dim; i++){
      for (j=0; matrix_dim > j; j++){
          if ( fabs(m[i*matrix_dim+j]-tmp[i*matrix_dim+j]) > 0.0001)
            printf("dismatch at (%d, %d): (o)%f (n)%f\n", i, j, m[i*matrix_dim+j], tmp[i*matrix_dim+j]);
      }
  }
  free(tmp);
}

