#include <stdio.h>
#include <unistd.h>
#include <getopt.h>
#include <stdlib.h>
#include <assert.h>

#include "common.h"

static int do_verify = 0;
int omp_num_threads = 40;

static struct option long_options[] = {

  {"input", 1, NULL, 'i'},
  {"size", 1, NULL, 's'},
  {"verify", 0, NULL, 'v'},
  {0,0,0,0}
};

extern void
lud_omp(float *m, int matrix_dim);

__global__ void lud_diagonal_kernel(float* a, int size, int offset) {
    const int BS = 16;
    int i = threadIdx.x;
    if (i >= BS) return;

    // Diagonal block LU factorization
    for (int j = i; j < BS; j++) {
        float sum = 0.f;
        for (int k = 0; k < i; k++) {
            sum += a[(offset + i)*size + offset + k] * a[(offset + k)*size + offset + j];
        }
        a[(offset + i)*size + offset + j] -= sum;
    }

    __syncthreads();

    float temp = 1.f / a[(offset + i)*size + offset + i];
    for (int j = i + 1; j < BS; j++) {
        float sum = 0.f;
        for (int k = 0; k < i; k++) {
            sum += a[(offset + j)*size + offset + k] * a[(offset + k)*size + offset + i];
        }
        a[(offset + j)*size + offset + i] = (a[(offset + j)*size + offset + i] - sum) * temp;
    }
}

__global__ void lud_perimeter_kernel(float* a, int size, int offset, int chunks_in_inter_row) {
    const int BS = 16;
    int chunk_idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (chunk_idx >= chunks_in_inter_row) return;

    // Update perimeter blocks: row and column blocks adjacent to diagonal block
    // Load diagonal block row into shared memory temp
    __shared__ float temp[BS * BS];
    int i, j, k;

    // Load row block (offset row, offset+BS*chunk_idx col)
    for (i = 0; i < BS; i++) {
        for (j = 0; j < BS; j++) {
            temp[i*BS + j] = a[(offset + i)*size + offset + j];
        }
    }
    __syncthreads();

    int i_global = offset;
    int j_global = offset + BS * (chunk_idx + 1);

    // Update row blocks
    for (j = 0; j < BS; j++) {
        for (i = 0; i < BS; i++) {
            float sum = 0.f;
            for (k = 0; k < i; k++) {
                sum += temp[i*BS + k] * a[(i_global + k)*size + j_global + j];
            }
            a[(i_global + i)*size + j_global + j] -= sum;
        }
    }

    // Update column blocks
    j_global = offset;
    i_global = offset + BS * (chunk_idx + 1);

    for (i = 0; i < BS; i++) {
        for (j = 0; j < BS; j++) {
            float sum = 0.f;
            for (k = 0; k < j; k++) {
                sum += a[(i_global + i)*size + j_global + k] * temp[k*BS + j];
            }
            a[(i_global + i)*size + j_global + j] = (a[(i_global + i)*size + j_global + j] - sum) / a[(offset + j)*size + offset + j];
        }
    }
}

__global__ void lud_internal_kernel(float* a, int size, int offset, int chunks_in_inter_row) {
    const int BS = 16;
    int chunk_idx = blockIdx.x * blockDim.x + threadIdx.x;
    int chunks_per_inter = chunks_in_inter_row * chunks_in_inter_row;
    if (chunk_idx >= chunks_per_inter) return;

    int i_global = offset + BS * (1 + chunk_idx / chunks_in_inter_row);
    int j_global = offset + BS * (1 + chunk_idx % chunks_in_inter_row);

    float temp_top[BS*BS];
    float temp_left[BS*BS];
    float sum[BS] = {0.f};

    // Load top and left blocks
    for (int i = 0; i < BS; i++) {
        for (int j = 0; j < BS; j++) {
            temp_top[i*BS + j] = a[(offset + i)*size + j_global + j];
            temp_left[i*BS + j] = a[(i_global + i)*size + offset + j];
        }
    }

    // Compute update
    for (int i = 0; i < BS; i++) {
        for (int k = 0; k < BS; k++) {
            for (int j = 0; j < BS; j++) {
                sum[j] += temp_left[i*BS + k] * temp_top[k*BS + j];
            }
        }
        for (int j = 0; j < BS; j++) {
            a[(i_global + i)*size + j_global + j] -= sum[j];
            sum[j] = 0.f;
        }
    }
}

void lud_omp(float *a, int size)
{
    const int BS = 16;
    int offset;

    for (offset = 0; size - BS > offset ; offset += BS)
    {
        // Launch diagonal kernel with BS threads
        lud_diagonal_kernel<<<1, BS>>>(a, size, offset);
        cudaDeviceSynchronize();

        int size_inter = size - offset - BS;
        int chunks_in_inter_row = size_inter / BS;

        if (chunks_in_inter_row > 0) {
            int threads = 256;
            int blocks = (chunks_in_inter_row + threads - 1) / threads;
            lud_perimeter_kernel<<<blocks, threads>>>(a, size, offset, chunks_in_inter_row);
            cudaDeviceSynchronize();

            int chunks_per_inter = chunks_in_inter_row * chunks_in_inter_row;
            blocks = (chunks_per_inter + threads - 1) / threads;
            lud_internal_kernel<<<blocks, threads>>>(a, size, offset, chunks_in_inter_row);
            cudaDeviceSynchronize();
        }
    }

    // Final diagonal block
    int remaining = size - offset;
    if (remaining > 0) {
        lud_diagonal_kernel<<<1, BS>>>(a, size, offset);
        cudaDeviceSynchronize();
    }
}

int
main ( int argc, char *argv[] )
{
  int matrix_dim = 32; 
  int opt, option_index=0;
  func_ret_t ret;
  const char *input_file = NULL;
  float *m, *mm;
  stopwatch sw;


  while ((opt = getopt_long(argc, argv, "::vs:n:i:", 
                            long_options, &option_index)) != -1 ) {
    switch(opt){
    case 'i':
      input_file = optarg;
      break;
    case 'v':
      do_verify = 1;
      break;
    case 'n':
      omp_num_threads = atoi(optarg);
      break;
    case 's':
      matrix_dim = atoi(optarg);
      printf("Generate input matrix internally, size =%d\n", matrix_dim);



      break;
    case '?':
      fprintf(stderr, "invalid option\n");
      break;
    case ':':
      fprintf(stderr, "missing argument\n");
      break;
    default:
      fprintf(stderr, "Usage: %s [-v] [-s matrix_size|-i input_file]\n",
	      argv[0]);
      exit(EXIT_FAILURE);
    }
  }

  if ( (optind < argc) || (optind == 1)) {
    fprintf(stderr, "Usage: %s [-v] [-n no. of threads] [-s matrix_size|-i input_file]\n", argv[0]);
    exit(EXIT_FAILURE);
  }

  if (input_file) {
    printf("Reading matrix from file %s\n", input_file);
    ret = create_matrix_from_file(&m, input_file, &matrix_dim);
    if (ret != RET_SUCCESS) {
      m = NULL;
      fprintf(stderr, "error create matrix from file %s\n", input_file);
      exit(EXIT_FAILURE);
    }
  }
  else if (matrix_dim) {
    printf("Creating matrix internally size=%d\n", matrix_dim);
    ret = create_matrix(&m, matrix_dim);
    if (ret != RET_SUCCESS) {
      m = NULL;
      fprintf(stderr, "error create matrix internally size=%d\n", matrix_dim);
      exit(EXIT_FAILURE);
    }
  }

  else {
    printf("No input file specified!\n");
    exit(EXIT_FAILURE);
  } 

  if (do_verify){
    printf("Before LUD\n");

    matrix_duplicate(m, &mm, matrix_dim);
  }


  stopwatch_start(&sw);
  lud_omp(m, matrix_dim);
  stopwatch_stop(&sw);
  printf("Time consumed(ms): %lf\n", 1000*get_interval_by_sec(&sw));

  if (do_verify){
    printf("After LUD\n");

    printf(">>>Verify<<<<\n");
    lud_verify(mm, m, matrix_dim); 
    free(mm);
  }

  free(m);

  return EXIT_SUCCESS;
}
